 JOIN SJob.RibaStages AS [FC51FD71-51A1-4B7A-BA50-F0C2F2816225] ON ([FC51FD71-51A1-4B7A-BA50-F0C2F2816225].ID = root_hobt.AppointmentFromRibaStageId) 
