UPDATE SCore.EntityQueries SET Statement = N'SELECT	root_hobt.ID,
		root_hobt.SchemaName,
		root_hobt.TableName,
		root_hobt.ColumnName,
		root_hobt.RowID,
		root_hobt.Datetime,
		i.Guid AS UserID,
		root_hobt.SQLUser,
		root_hobt.PreviousValue,
		root_hobt.NewValue,
		ep.Guid AS EntityPropertyID,
		root_hobt.Guid,
		root_hobt.RowVersion,
		root_hobt.RowStatus,
		root_hobt.RowGuid
FROM	SCore.RecordHistory root_hobt
JOIN	SCore.Identities i ON (i.ID = root_hobt.UserID)
JOIN	SCore.EntityProperties ep ON (ep.ID = root_hobt.EntityPropertyID)' WHERE ID = 162
UPDATE SCore.EntityQueries SET Statement = N'SELECT
        root_hobt.ID,
