--
-- Updating data of table [SUserInterface].[DropDownListDefinitions]
--
UPDATE SUserInterface.DropDownListDefinitions SET SqlQuery = N'SELECT  root_hobt.Name, root_hobt.Guid 
FROM    Score.EntityPropertyGroups root_hobt 
WHERE   ((EXISTS
            (
                SELECT  1
                FROM    SCore.EntityProperties ep 
                JOIN    SCore.EntityHoBTs h on (ep.EntityHoBTID = h.ID)
                WHERE   (ep.Guid = ''[[RecordGuid]]'')
                    AND (h.EntityTypeID = root_hobt.EntityTypeID)
            )
        ) OR (ID = -1))' WHERE ID = 3
UPDATE SUserInterface.DropDownListDefinitions SET SqlQuery = N'SELECT	root_hobt.Guid,
		N''['' + h.SchemaName + ''].['' + h.ObjectName + ''].['' + root_hobt.Name + '']'' AS Name
FROM	SCore.EntityProperties AS root_hobt
JOIN	SCore.EntityHobts h ON (h.ID = root_hobt.EntityHoBTID)
WHERE	(root_hobt.Id = root_hobt.ID)
	OR	(root_hobt.Guid = ''[[CurrentSelectedValueGuid]]'')' WHERE ID = 9
UPDATE SUserInterface.DropDownListDefinitions SET SqlQuery = N'SELECT
        root_hobt.Guid,
        root_hobt.Name
FROM
        SCore.EntityProperties root_hobt
    JOIN
        SCore.EntityHoBTs      h
            ON (root_hobt.EntityHoBTID = h.ID)
    JOIN
        SCore.EntityQueries    eq
            ON (h.EntityTypeID = eq.EntityTypeID)
WHERE
        (
            (eq.Guid = ''[[ParentGuid]]'')
            AND (''[[ParentGuid]]'' != ''00000000-0000-0000-0000-000000000000'')
        )
        OR
            (
                (''[[ParentGuid]]'' = ''00000000-0000-0000-0000-000000000000'')
                AND ((EXISTS
    (
        SELECT
            1
        FROM
            SCore.EntityQueryParameters eqp
        WHERE
            (eqp.Guid = ''[[RecordGuid]]'')
            AND (eq.ID = eqp.EntityQueryID)
    )
                     )
                    )
            )' WHERE ID = 10
UPDATE SUserInterface.DropDownListDefinitions SET SqlQuery = N'SELECT root_hobt.Code, root_hobt.Guid
FROM SUserInterface.GridDefinitions root_hobt' WHERE ID = 11
UPDATE SUserInterface.DropDownListDefinitions SET SqlQuery = N'SELECT root_hobt.Name, root_hobt.Guid
FROM SUserInterface.MetricTypes root_hobt' WHERE ID = 12
UPDATE SUserInterface.DropDownListDefinitions SET SqlQuery = N'SELECT  olfu.Label AS [Name],
        root_hobt.Guid
FROM    SUserInterface.GridViewDefinitions root_hobt
OUTER APPLY	SCore.ObjectLabelForUser(root_hobt.LanguageLabelId,[[UserId]]) olfu' WHERE ID = 13
UPDATE SUserInterface.DropDownListDefinitions SET SqlQuery = N'SELECT root_hobt.Guid,
       root_hobt.FullName
